#include <bits/stdc++.h>
#define ll long long
using namespace std;

const int N=1e5+10;

int n;
ll a[N],b[N],lcm=1,ans;

ll exgcd(ll a,ll b,ll &x,ll &y){
    if(b==0){
        x=1,y=0;
        return a;
    }
    ll gcd=exgcd(b,a%b,x,y),z=x;
    x=y,y=z-a/b*y;
    return gcd;
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%lld%lld",&a[i],&b[i]);
        b[i]%=a[i];
    }
    for(int i=1;i<=n;i++){
        b[i]=(b[i]-ans)%a[i];
        ll x,y,gcd,t=lcm;
        gcd=exgcd(lcm,a[i],x,y);
        lcm=(__int128)lcm*a[i]/__gcd(lcm,a[i]);
        //printf("%lld*%lld \\equiv %lld (mod %lld)\n",t,x,gcd,a[i]);
        ans=(ans+(__int128)t*x%lcm*(b[i]/gcd)%lcm)%lcm;
    }
    printf("%lld",(ans+lcm)%lcm);
    return 0;
}
